import tensorflow as tf
import pandas as pd
import numpy as np
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
from PIL import Image
import uuid
from sklearn.model_selection import train_test_split
import json

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Create upload directory
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Global model and data storage
model = None
class_labels = []
training_data = []

def create_model(num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(224, 224, 3)),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(128, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(512, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(optimizer='adam',
                  loss='categorical_crossentropy',
                  metrics=['accuracy'])
    return model

def load_and_preprocess_data(csv_path, image_folder):
    df = pd.read_csv(csv_path)
    images = []
    labels = []
    
    for _, row in df.iterrows():
        try:
            img_path = os.path.join(image_folder, row['image_name'])
            img = Image.open(img_path).convert('RGB')
            img = img.resize((224, 224))
            img_array = np.array(img)
            images.append(img_array)
            labels.append(row['label'])
        except Exception as e:
            print(f"Error loading image {row['image_name']}: {e}")
            continue
    
    return np.array(images), np.array(labels)

def train_model():
    global model, class_labels
    
    # Load training data
    csv_path = os.path.join(app.config['UPLOAD_FOLDER'], 'training_data.csv')
    image_folder = os.path.join(app.config['UPLOAD_FOLDER'], 'images')
    
    if not os.path.exists(csv_path) or not os.path.exists(image_folder):
        return False
    
    try:
        X, y = load_and_preprocess_data(csv_path, image_folder)
        
        # Encode labels
        unique_labels = np.unique(y)
        class_labels = unique_labels.tolist()
        label_to_idx = {label: idx for idx, label in enumerate(class_labels)}
        y_encoded = np.array([label_to_idx[label] for label in y])
        y_categorical = tf.keras.utils.to_categorical(y_encoded, num_classes=len(class_labels))
        
        # Split data
        X_train, X_test, y_train, y_test = train_test_split(
            X, y_categorical, test_size=0.2, random_state=42
        )
        
        # Normalize images
        X_train = X_train.astype('float32') / 255.0
        X_test = X_test.astype('float32') / 255.0
        
        # Create and train model
        model = create_model(len(class_labels))
        
        model.fit(X_train, y_train,
                  epochs=10,
                  batch_size=32,
                  validation_data=(X_test, y_test),
                  verbose=1)
        
        return True
    except Exception as e:
        print(f"Training error: {e}")
        return False

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'csv_file' not in request.files or 'image_files' not in request.files:
        return jsonify({'error': 'Missing files'}), 400
    
    csv_file = request.files['csv_file']
    image_files = request.files.getlist('image_files')
    
    if csv_file.filename == '' or len(image_files) == 0:
        return jsonify({'error': 'No files selected'}), 400
    
    # Save CSV
    csv_filename = secure_filename(csv_file.filename)
    csv_path = os.path.join(app.config['UPLOAD_FOLDER'], csv_filename)
    csv_file.save(csv_path)
    
    # Save images
    image_folder = os.path.join(app.config['UPLOAD_FOLDER'], 'images')
    os.makedirs(image_folder, exist_ok=True)
    
    for image_file in image_files:
        if image_file:
            filename = secure_filename(image_file.filename)
            image_path = os.path.join(image_folder, filename)
            image_file.save(image_path)
    
    # Train model
    success = train_model()
    
    return jsonify({
        'message': 'Files uploaded and model trained successfully' if success else 'Model training failed',
        'model_trained': success
    })

@app.route('/contribute', methods=['POST'])
def contribute_example():
    global model, class_labels
    
    if 'image' not in request.files or 'label' not in request.form:
        return jsonify({'error': 'Missing image or label'}), 400
    
    image_file = request.files['image']
    label = request.form['label']
    
    if image_file.filename == '':
        return jsonify({'error': 'No image selected'}), 400
    
    # Save contribution
    filename = f"{uuid.uuid4()}.jpg"
    image_path = os.path.join(app.config['UPLOAD_FOLDER'], 'contributions', filename)
    os.makedirs(os.path.dirname(image_path), exist_ok=True)
    image_file.save(image_path)
    
    # Update training data
    contribution = {
        'image_name': filename,
        'label': label
    }
    
    # Add to training data
    training_data.append(contribution)
    
    # Retrain model
    success = train_model()
    
    return jsonify({
        'message': 'Contribution accepted and model retrained' if success else 'Model retraining failed',
        'retrained': success
    })

@app.route('/predict', methods=['POST'])
def predict():
    global model, class_labels
    
    if model is None:
        return jsonify({'error': 'Model not trained yet'}), 400
    
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    image_file = request.files['image']
    
    if image_file.filename == '':
        return jsonify({'error': 'No image selected'}), 400
    
    try:
        # Load and preprocess image
        img = Image.open(image_file).convert('RGB')
        img = img.resize((224, 224))
        img_array = np.array(img)
        img_array = img_array.astype('float32') / 255.0
        img_array = np.expand_dims(img_array, axis=0)
        
        # Make prediction
        predictions = model.predict(img_array)
        predicted_class_idx = np.argmax(predictions[0])
        confidence = predictions[0][predicted_class_idx]
        
        result = {
            'predicted_label': class_labels[predicted_class_idx],
            'confidence': float(confidence),
            'all_predictions': dict(zip(class_labels, predictions[0].tolist()))
        }
        
        return jsonify(result)
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)